// imply.sv:
module imply(input logic p, input logic q, output logic r);
  always_comb begin
    r = p | q;
  end
endmodule
// imply_tb.sv:
module imply_tb();
  logic p;
  logic q;
  logic r;

  imply dut(.p(p), .q(q), .r(r));

  initial begin
    p = 1;
    q = 0;
   $strobe("@%t: %d, %d, %d", $time, p, q, r);
  #1 $finish;
endmodule
// top.sv:
module top;
  imply_tb tb;
endmodule
